script.text:
			&ScriptQueryData;
			&ScriptVoucherInit;
			/* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;&VoucherLogHandleStatus;
	f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
	f._tabContainer._loaded = true;
	if (f._action == 'New') f.setItemValue('xs_name', f._extName);
	&ListCreate;
	&PostCreate;
	f.setReadOnlyFields('u_status, nguoi_duyet, comment, kieu_duyet');
	if (!f._$handleStatus) {
		var o = f.getItem('status');
		f._$handleStatus = [];
		for (var i = 0; i < o.options.length; i++) Array.add(f._$handleStatus, o.options[i]);
	}
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;&VoucherLogHandleStatus;
	if (f._action == 'New') f.setItemValue('xs_name', f._extName);
	f.setReadOnlyFields('u_status, nguoi_duyet, comment, kieu_duyet');
}
function close$Voucher$(f) {&ScriptCloseVoucher;
	&ListDispose;
	&PostDispose;
	if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
}
function on$Voucher$ExecuteCommand(sender, e) {
	var action = e.type.Action, f = sender, g = f.getItem('d91')._controlBehavior;
	switch (action)	{
		case 'Shown':
			&ListShown;
			&PostShown;
			break;
		case 'Gather':
			g.setSequenceNumber('line_nbr');
			g.setContinuance('stt_rec0');
			break;
		case 'Explore':
			var o = f.getItem('status');
			if (o.options.length < 7) for (var i = 3; i < 7; i++) o.options.add(f._$handleStatus[i]);
			&VoucherLogHandleStatusExplore;
			break;
		default:
			break;
	}
}

			&ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
	create: function(f) {
		var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d91')._controlBehavior;
		var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
		v.set_currencyFields('t_tien_nt:t_tien');
		v.addGridFields(g, 'gia_nt,tien_nt:gia,tien');
		v.addTotalFields(g, [['t_tien_nt', '[tien_nt]'], ['t_tien', 'tien']]);
		v.set_referenceFields(null);
&CurrencyDateChanged;
	onCurrencySelected: function(sender, e) {
		if (e.object._baseCurrency == e.type){
			e.object._form.focusWhenTabChanged([['d91', 'ma_vt']&ListTabChange;&PostTabChange;]);
			&PostCurrencySelected;
		}
	}
}


function onChange$Voucher$Tab(sender, e) {
	sender.parentForm.focusWhenTabChanged(['d91'&ListTabChange;&PostTabChange;, 'nguoi_duyet']);
	&PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$TransactionCode(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
function onChange$Voucher$ApprovingOfficers(o) {
	var f = o.parentForm;
	if ($func.trim(o.value) == '') f.setItemValue('user_id3', 0);
}
/* </flatten> */

function on$Voucher$ResponseComplete(sender, e) {
	var f = e.object, context = e.type.Context, result = e.type.Result;
	switch (context) {
		case 'Loading':
			&VoucherNumberLoading;
			set$Voucher$DefaultValue(f);
			break;
		case 'Scattering':
			&VoucherNumberScattering;
			set$Voucher$DefaultValue(f);
			&ListScattering;
			&PostScattering;
			break;
		case 'Navigating':
			&ListRefresh;
			&PostRefresh;
			break;

			&VoucherNumberReading;
			&CurrencyResponse;

		case 'Transaction':
			f.setItemValue('loai_ct', result[0].Value);
			break;
		&ListResponseTicket;
		default:
			break;
	}
}
/* <flatten type="Javascript"> */
function set$Voucher$DefaultValue(f) {
	var o = f.getItem('status');
	if ((f._action == 'New' || (f._action != 'View' && (o.value == '0' || o.value == '1'))) && o.options.length > 6) for (var i = 6; i > 2; i--) o.options.remove(i);
}
function when$VoucherCopying(f) {
	if (f.grid._dvHandle != null) f.setItemValue('status', f.grid._dvHandle);
	var a = 'stt_rec, u_status, ustatus_name, user_id3, nguoi_duyet, comment, kieu_duyet'.split(',');
	for (var i = 0; i < a.length; i++) {
		f.setItemValue($func.trim(a[i]), null);
	}
	f.getItem('ten_kieu%l').value = '';
}

function refresh$Status(f, s, u, name, description, approver, category) {
	var o = f.getItem('status'), c = $func.trim(category), o1 = f.getItemValue('nguoi_duyet'), o2 = f.getItemValue('kieu_duyet');
	if (o.options.length < 7) for (var i = 3; i < 7; i++) o.options.add(f._$handleStatus[i]);
	f.setItemValues('status, u_status, ustatus_name, nguoi_duyet, kieu_duyet', [s, u, name, approver, c]);
	if (o1 != approver) f.setReferenceKeyFilter('nguoi_duyet');
	if (o2 != c) f.setReferenceKeyFilter('kieu_duyet');

	var g = f.getItem('d91')._controlBehavior, l2 = g._getColumnOrder('xstatus_name%l'), l3 = g._getColumnOrder('so_luong'), l4 = g._getColumnOrder('sl_duyet');
	for(var row = 1; row <= g._rowCount; row ++) {
		g._setItemValue(row, l2, description);
		if (o.value != '0' && o.value != '1' && g._getItemValue(row, l4) == 0) g._setItemValue(row, l4, g._getItemValue(row, l3));
	}
}
/* </flatten> */
